    apollo_person_id: p.apollo_person_id,
    apollo_payload: {
      person_id: p.apollo_person_id,
      label_names: [`geoperf:${p.sous_cat_slug}`, `score-${p.visibility_score || 0}-of-4`, `rank-${p.rank || 'unknown'}`]
